def generate_report(rubric: Dict[str, Dict[str, Any]]) -> str:
    r = {
        "overall_summary": "Overall report on student submission:",
        "criteria_feedback": []
    }
    for criterion, details in rubric.items():
        r["criteria_feedback"].append({
            "criterion_id": criterion,
            "rating": details.get("rating", "excellent"),
            "evidence": [f"{k}: {v}" for k, v in details.get("evidence", {}).items()],
            "improvement_tip": details.get("improvement_tip", "")
        })
    return json.dumps(r)
